base_date = datetime(2024, 1, 1)
date_range = [base_date + timedelta(days=i) for i in range(365)]
rows = []
job_id = 0
for role, config in roles.items():
    n_jobs = random.randint(18, 25)
    for _ in range(n_jobs):
        job_id += 1
        desc = random.choice(config['descriptions'])
        posted = random.choice(date_range)
        rows.append({'job_title': role, 'company': random.choice(config['companies']), 'location': random.choice(config['locations']), 'experience': random.choice(config['experience']), 'salary': random.choice(config['salary']), 'posted_date': posted.strftime('%Y-%m-%d'), 'description': desc})
random.shuffle(rows)
output = '/home/arnab05/Documents/SkillGraph/ml/data/sample/sample_jobs.csv'
with open(output, 'w', newline='', encoding='utf-8') as f:
    writer = csv.DictWriter(f, fieldnames=['job_title', 'company', 'location', 'experience', 'salary', 'posted_date', 'description'])
    writer.writeheader()
    writer.writerows(rows)
print(f'Generated {len(rows)} job postings to {output}')